// MARK: - WKScriptMessageHandler via LeakAvoider

private final class LeakAvoider: NSObject, WKScriptMessageHandler {
    weak var delegate: WKScriptMessageHandler?
    
    init(delegate: WKScriptMessageHandler) {
        self.delegate = delegate
        super.init()
    }
    
    func userContentController(_ userContentController: WKUserContentController,
                               didReceive message: WKScriptMessage) {
        delegate?.userContentController(userContentController, didReceive: message)
    }
}

// MARK: - WKScriptMessageHandler

extension HybridWebViewController: WKScriptMessageHandler {
    
    func userContentController(_ userContentController: WKUserContentController,
                               didReceive message: WKScriptMessage) {
        // SECURITY: Verify the message comes from an allowed origin
        guard message.name == SecureWebViewConfiguration.bridgeHandlerName else {
            print("[Bridge] Rejected message from unknown handler: \(message.name)")
            return
        }
        
        // Verify the frame's origin
        if #available(iOS 14.0, *) {
            guard let frameInfo = Optional(message.frameInfo),
                  frameInfo.isMainFrame else {
                print("[Bridge] Rejected message from non-main frame")
                return
            }
        }
        
        // Verify current webView URL is from allowed origin
        guard SecureWebViewConfiguration.isAllowedOrigin(webView.url) else {
            print("[Bridge] Rejected message: WebView URL is not from allowed origin")
            return
        }
        
        // Parse and validate the message
        guard let body = message.body as? [String: Any],
              let bridgeMessage = BridgeMessage(from: body) else {
            print("[Bridge] Rejected malformed message")
            return
        }
        
        // Route to appropriate handler
        switch bridgeMessage.action {
        case .requestCamera:
            handleCameraRequest(callbackId: bridgeMessage.callbackId)
        case .requestPushNotifications:
            handlePushNotificationRequest(callbackId: bridgeMessage.callbackId)
        case .initiateInAppPurchase:
            handleInAppPurchase(payload: bridgeMessage.payload, callbackId: bridgeMessage.callbackId)
        case .getDeviceInfo:
            handleDeviceInfoRequest(callbackId: bridgeMessage.callbackId)
        }
    }
}

// MARK: - WKNavigationDelegate

extension HybridWebViewController: WKNavigationDelegate {
    
    func webView(_ webView: WKWebView,
                 decidePolicyFor navigationAction: WKNavigationAction,
                 decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        
        guard let url = navigationAction.request.url else {
            decisionHandler(.cancel)
            return
        }
        
        // Only allow HTTPS navigation to approved domains
        if SecureWebViewConfiguration.isAllowedNavigationDomain(url) {
            decisionHandler(.allow)
            return
        }
        
        // For external links (e.g., from target="_blank" or user taps), open in Safari
        if let scheme = url.scheme?.lowercased(), (scheme == "https" || scheme == "http") {
            // Open external links in the system browser
            UIApplication.shared.open(url, options: [:], completionHandler: nil)
        }
        
        decisionHandler(.cancel)
    }
    
    func webView(_ webView: WKWebView,
                 decidePolicyFor navigationResponse: WKNavigationResponse,
                 decisionHandler: @escaping (WKNavigationResponsePolicy) -> Void) {
        
        // Verify HTTPS response
        if let httpResponse = navigationResponse.response as? HTTPURLResponse {
            let statusCode = httpResponse.statusCode
            if statusCode >= 400 {
                print("[Navigation] Received error status code: \(statusCode)")
                // Still allow so we can show error page from our server
            }
        }
        
        // Verify the response URL is from an allowed domain
        if let url = navigationResponse.response.url,
           SecureWebViewConfiguration.isAllowedNavigationDomain(url) {
            decisionHandler(.allow)
        } else {
            decisionHandler(.cancel)
        }
    }
    
    func webView(_ webView: WKWebView,
                 didReceive challenge: URLAuthenticationChallenge,
                 completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        // Perform standard TLS validation - do NOT bypass certificate checks
        guard let serverTrust = challenge.protectionSpace.serverTrust,
              challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        // Validate the server trust using the system's default policy
        let host = challenge.protectionSpace.host
        let policy = SecTrustCreateWithCertificates(serverTrust, SecPolicyCreateSSL(true, host as CFString))
        
        guard policy == errSecSuccess else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        var error: CFError?
        if SecTrustEvaluateWithError(serverTrust, &error) {
            completionHandler(.useCredential, URLCredential(trust: serverTrust))
        } else {
            print("[TLS] Certificate validation failed for \(host): \(error?.localizedDescription ?? "unknown")")
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
    
    func webView(_ webView: WKWebView, didStartProvisionalNavigation navigation: WKNavigation!) {
        activityIndicator?.startAnimating()
    }
    
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        activityIndicator?.stopAnimating()
    }
    
    func webView(_ webView: WKWebView, didFailProvisionalNavigation navigation: WKNavigation!, withError error: Error) {
        activityIndicator?.stopAnimating()
        showErrorAlert(message: "Failed to load. Please check your connection and try again.")
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        activityIndicator?.stopAnimating()
    }
    
    private func showErrorAlert(message: String) {
        let alert = UIAlertController(title: "Connection Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Retry", style: .default) { [weak self] _ in
            self?.loadMainContent()
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
}

// MARK: - WKUIDelegate

extension HybridWebViewController: WKUIDelegate {
    
    // Handle JavaScript alerts securely
    func webView(_ webView: WKWebView,
                 runJavaScriptAlertPanelWithMessage message: String,
                 initiatedByFrame frame: WKFrameInfo,
                 completionHandler: @escaping () -> Void) {
        
        guard SecureWebViewConfiguration.isAllowedOrigin(frame.request.url) else {
            completionHandler()
            return
        }
        
        let truncatedMessage = String(message.prefix(500))
        let alert = UIAlertController(title: nil, message: truncatedMessage, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler()
        })
        present(alert, animated: true)
    }
    
    // Handle JavaScript confirm dialogs
    func webView(_ webView: WKWebView,
                 runJavaScriptConfirmPanelWithMessage message: String,
                 initiatedByFrame frame: WKFrameInfo,
                 completionHandler: @escaping (Bool) -> Void) {
        
        guard SecureWebViewConfiguration.isAllowedOrigin(frame.request.url) else {
            completionHandler(false)
            return
        }
        
        let truncatedMessage = String(message.prefix(500))
        let alert = UIAlertController(title: nil, message: truncatedMessage, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(true)
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(false)
        })
        present(alert, animated: true)
    }
    
    // Prevent new windows from being opened
    func webView(_ webView: WKWebView,
                 createWebViewWith configuration: WKWebViewConfiguration,
                 for navigationAction: WKNavigationAction,
                 windowFeatures: WKWindowFeatures) -> WKWebView? {
        // Don't create new web views; load in the existing one if it's an allowed domain
        if let url = navigationAction.request.url,
           SecureWebViewConfiguration.isAllowedNavigationDomain(url) {
            webView.load(navigationAction.request)
        } else if let url = navigationAction.request.url {
            UIApplication.shared.open(url, options: [:], completionHandler: nil)
        }
        return nil
    }
}

