    func imagePickerController(_ picker: UIImagePickerController,
                               didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey: Any]) {
        let callbackId = objc_getAssociatedObject(picker, &AssociatedKeys.callbackId) as? String
        
        picker.dismiss(animated: true) { [weak self] in
            if let image = info[.originalImage] as? UIImage,
               let imageData = image.jpegData(compressionQuality: 0.8) {
                let base64String = imageData.base64EncodedString()
                self?.sendBridgeResponse(callbackId: callbackId, success: true,
                                       data: ["imageBase64": base64String, "mimeType": "image/jpeg"])
            } else {
                self?.sendBridgeResponse(callbackId: callbackId, success: false,
                                       data: ["error": "Failed to process captured image"])
            }
        }
    }
    
    func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
        let callbackId = objc_getAssociatedObject(picker, &AssociatedKeys.callbackId) as? String
        picker.dismiss(animated: true) { [weak self] in
            self?.sendBridgeResponse(callbackId: callbackId, success: false,
                                   data: ["error": "Camera cancelled by user"])
        }
    }
}

// MARK: - In-App Purchase Manager

final class InAppPurchaseManager: NSObject, SKProductsRequestDelegate, SKPaymentTransactionObserver {
    
    private var products: [String: SKProduct] = [:]
    private var purchaseCompletionHandlers: [String: (Result<String, Error>) -> Void] = [:]
    private let purchaseQueue = DispatchQueue(label: "com.yourcompany.iap.queue")
    
    // Whitelist of valid product IDs
    private let validProductIds: Set<String> = [
        "com.yourcompany.app.premium.monthly",
        "com.yourcompany.app.premium.yearly",
        "com.yourcompany.app.credits.100",
        "com.yourcompany.app.credits.500"
    ]
    
    override init() {
        super.init()
        SKPaymentQueue.default().add(self)
    }
    
    deinit {
        SKPaymentQueue.default().remove(self)
    }
    
    func purchase(productId: String, completion: @escaping (Result<String, Error>) -> Void) {
        // Validate against whitelist
        guard validProductIds.contains(productId) else {
            completion(.failure(NSError(domain: "IAP", code: -1,
                                       userInfo: [NSLocalizedDescriptionKey: "Invalid product identifier"])))
            return
        }
        
        guard SKPaymentQueue.canMakePayments() else {
            completion(.failure(NSError(domain: "IAP", code: -2,
                                       userInfo: [NSLocalizedDescriptionKey: "In-app purchases are disabled"])))
            return
        }
        
        purchaseQueue.sync {
            purchaseCompletionHandlers[productId] = completion
        }
        
        // Fetch product info first
        let request = SKProductsRequest(productIdentifiers: [productId])
        request.delegate = self
        request.start()
    }
    
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        for product in response.products {
            products[product.productIdentifier] = product
            let payment = SKPayment(product: product)
            SKPaymentQueue.default().add(payment)
        }
        
        for invalidId in response.invalidProductIdentifiers {
            purchaseQueue.sync {
                let handler = purchaseCompletionHandlers.removeValue(forKey: invalidId)
                handler?(.failure(NSError(domain: "IAP", code: -3,
                                         userInfo: [NSLocalizedDescriptionKey: "Invalid product: \(invalidId)"])))
            }
        }
    }
    
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            let productId = transaction.payment.productIdentifier
            
            switch transaction.transactionState {
            case .purchased:
                let transactionId = transaction.transactionIdentifier ?? "unknown"
                queue.finishTransaction(transaction)
                purchaseQueue.sync {
                    let handler = purchaseCompletionHandlers.removeValue(forKey: productId)
                    handler?(.success(transactionId))
                }
                
            case .failed:
                queue.finishTransaction(transaction)
                purchaseQueue.sync {
                    let handler = purchaseCompletionHandlers.removeValue(forKey: productId)
                    handler?(.failure(transaction.error ?? NSError(domain: "IAP", code: -4,
                                                                    userInfo: [NSLocalizedDescriptionKey: "Purchase failed"])))
                }
                
            case .restored:
                queue.finishTransaction(transaction)
                
            case .deferred, .purchasing:
                break
                
            @unknown default:
                break
            }
        }
    }
    
    func request(_ request: SKRequest, didFailWithError error: Error) {
        // Clean up all pending handlers on request failure
        purchaseQueue.sync {
            for (_, handler) in purchaseCompletionHandlers {
                handler(.failure(error))
            }
            purchaseCompletionHandlers.removeAll()
        }
    }
}

